import pytest
from source import get_user_display_name

def test_get_user_display_name_with_none_profile_returns_none():
    """When profile is explicitly None, the function should return None instead of raising."""
    user_data = {"profile": None}
    result = get_user_display_name(user_data)
    assert result is None, (
        "Expected get_user_display_name to return None when 'profile' is None, "
        f"but got {result!r}"
    )

